/**
 * Matches a potential JSONPath (also incomplete ones like `content$.`)
 * https://regex101.com/r/9QQvzF/1
 * @internal
 */
export const JSONPATH_PATTERN_PARTIAL =
  /^(?:"(?:[^"\\]|\\.)*"|[^\s"$]+)\$(?:(?:\.(?:[a-zA-Z_][\w]*|"(?:[^"\\]|\\.)*")|\[(?:\d+|"(?:[^"\\]|\\.)*")\])*)/;

/**
 * Text values that represent a search operator at any stage of typing.
 * Used to determine when to show search operator suggestions.
 */
const SEARCH_OPERATOR_VALUES = ['', '*', '* ', '*~', '* ~'];
const isSearchOperatorValue = (value: string) =>
  SEARCH_OPERATOR_VALUES.includes(value);

/**
 * The return type of `getKeySuggestions`.
 * An ordered array of suggestion groups in declaration order. Empty groups are omitted.
 * The trailing entry (if present) holds the "use as key" hint, merged into the last implicit group.
 */
type KeySuggestionsResult = SuggestionGroup<FilterFieldSuggestionProps>[];

/**
 * Lists all defined filter keys
 * @internal
 */
export function getKeySuggestions(
  internalValidatorMap: InternalValidatorMap | undefined,
  suggestionTypes: FilterFieldSuggestionType = [],
  customTypes?: FilterFieldCustomTypes,
  doc?: string,
  currentToken?: FilterFieldValueNode,
): KeySuggestionsResult {
  const validatorMapIsExhaustive = internalValidatorMap?.exhaustive;
  let textValue = currentToken?.textValue ?? '';
  const hasTrailingSpace = textValue.endsWith(' ');

  // ORs and ANDs require a special handling. Once we detect a logical operator,
  // we get the actual text value (instead of what's in the token).
  const textValueNeedsEscaping =
    textValue.toLocaleLowerCase() === 'or' ||
    textValue.toLocaleLowerCase() === 'and';

  if (textValue && textValueNeedsEscaping && doc && currentToken) {
    textValue = doc
      .slice(currentToken.range.from, currentToken.range.to)
      .toString();
  }

  // No validator map — use-as-key / start-typing suggestion in the default group.
  if (!internalValidatorMap) {
    if (
      textValue &&
      !validatorMapIsExhaustive &&
      !hasTrailingSpace &&
      !isSearchOperatorValue(textValue)
    ) {
      return [
        {
          id: KEY_GROUP_ID,
          suggestions: [
            getDefaultKeySuggestion(textValue, textValueNeedsEscaping),
          ],
        },
      ];
    } else if (!textValue && !validatorMapIsExhaustive) {
      return [
        { id: KEY_GROUP_ID, suggestions: [getStartTypingSuggestion('key')] },
      ];
    }
    return [];
  }

  const { byKey, keyToGroup } = internalValidatorMap.normalizedKeys;

  // Result is built lazily: a group entry is only created when its first suggestion
  // is pushed into it, so empty groups never appear and no filter pass is needed.
  // Declaration order is preserved because byKey is populated in declaration order
  // during normalization.
  const groupEntryById = new Map<string, KeySuggestionsResult[number]>();
  const result: KeySuggestionsResult = [];

  let suggestionMatchesTextValue = false;

  // Iterate over all key suggestions and push them directly into the correct group.
  for (const [key, config] of byKey) {
    if (key === textValue) {
      suggestionMatchesTextValue = true;
    }

    // Determine the icon type: an explicit valueType takes precedence to avoid
    // iterating over all valuePredicate entries. Fall back to valuePredicate
    // inference only when no valueType is set.
    // DEPRECATION: [APPDEV-16872] BREAKING-CHANGE
    // TODO: Fallback can be removed once the deprecated FilterFieldValidatorMapTypePredicate format is removed and all key predicates use the new explicit valueType.
    let suggestionTypeResult: ReturnType<typeof getValidValueTypes>;

    if (config.valueType) {
      suggestionTypeResult = getValidValueTypes({ type: config.valueType });
    } else if (config.valuePredicate) {
      suggestionTypeResult = getValidValueTypes(config.valuePredicate);
    } else {
      suggestionTypeResult = {
        suggestionType: 'Any',
        hasLiteralValues: false,
        types: ['Any'],
      };
    }
    const { suggestionType, hasLiteralValues } = suggestionTypeResult;
    const displayValue = config.displayValue;
    const details = config.details;

    let keySuggestion:
      | FilterFieldSuggestionProps
      | FilterFieldSuggestionProps[];

    if (suggestionType === 'JSONPath') {
      // JSONPath key suggestions intentionally use their built-in details text.
      keySuggestion = getJSONPathKeySuggestion(key, suggestionType);
    } else if (Array.isArray(suggestionType)) {
      keySuggestion = suggestionType.map((type) => {
        if (type === 'JSONPath') {
          // JSONPath key suggestions intentionally use their built-in details text.
          return getJSONPathKeySuggestion(key, type);
        }

        return {
          value: key,
          icon: getIconForValueType(type),
          suggestionType: 'validatorMap' as const,
          displayValue,
          details,
        };
      });
    } else if (hasLiteralValues && Array.isArray(config.valuePredicate)) {
      // Valid values are defined in an array. We don't loop over the whole
      // array to infer the type, but just use 'Any'.
      keySuggestion = {
        value: key,
        icon: getIconForValueType('Any'),
        suggestionType: 'validatorMap',
        displayValue,
        details,
      };
    } else {
      keySuggestion = {
        value: key,
        icon: getIconForValueType(suggestionType, customTypes),
        suggestionType: 'validatorMap' as const,
        displayValue,
        details,
      };
    }

    const keySuggestions = Array.isArray(keySuggestion)
      ? keySuggestion
      : [keySuggestion];

    const group = keyToGroup.get(key);

    if (group === undefined) {
      continue;
    }

    let groupEntry = groupEntryById.get(group.id);

    if (!groupEntry) {
      groupEntry = {
        id: group.id,
        label: group.label,
        'aria-label': group['aria-label'],
        suggestions: [],
      };
      groupEntryById.set(group.id, groupEntry);
      result.push(groupEntry);
    }

    groupEntry.suggestions.push(...keySuggestions);
  }

  // Append "use as key" suggestion so it always appears last, after all named groups.
  // It is merged into the last implicit group to avoid rendering a divider between key
  // suggestions and the fallback. If the last group is explicit, a new implicit group is
  // created instead.
  // When the token is a JSONPath expression, only render the JSONPath suggestion and omit the "use as key" suggestion.
  const isJSONPathContinuation =
    currentToken?.type === 'JSONPath' ||
    (currentToken?.type === 'Error' &&
      JSONPATH_PATTERN_PARTIAL.test(currentToken?.textValue ?? ''));

  if (
    textValue &&
    !validatorMapIsExhaustive &&
    !suggestionMatchesTextValue &&
    !isSearchOperatorValue(textValue) &&
    (!hasTrailingSpace || suggestionTypes.includes('pastedContent')) &&
    !isJSONPathContinuation
  ) {
    const trailingSuggestion = getDefaultKeySuggestion(
      textValue,
      textValueNeedsEscaping,
    );
    const lastGroup = result.at(-1);

    if (lastGroup?.id.startsWith(`${KEY_GROUP_ID}-implicit-`)) {
      // Merge into the last implicit group.
      lastGroup.suggestions.push(trailingSuggestion);
    } else {
      // Last group is explicit; create new implicit group to render the divider.
      result.push({
        id: `${KEY_GROUP_ID}-implicit-${result.length}`,
        suggestions: [trailingSuggestion],
      });
    }
  }

  return result;
}

/** @internal */
export function getSearchSuggestions(
  context: CompletionContext,
  currentStatement: FilterFieldStatementNode | undefined,
  currentToken: FilterFieldValueNode,
  suggestionTypes: FilterFieldSuggestionType,
  isInsideAGroup: boolean,
): FilterFieldSuggestionProps[] {
  if (isInsideAGroup) {
    return [];
  }

  const textValue = currentToken.textValue;
  const { value } = currentToken;

  if (
    (currentStatement?.comparisonOperator !== undefined &&
      currentStatement.comparisonOperator.type !== 'SearchOperator') ||
    (currentStatement?.comparisonOperator?.type === 'SearchOperator' &&
      value === '')
  ) {
    return [];
  }

  const emptyInput = context.state.doc.toString() === '';

  if (emptyInput || isSearchOperatorValue(textValue)) {
    return [getSearchSuggestion()];
  } else if (
    (suggestionTypes.includes('key') ||
      suggestionTypes.includes('value') ||
      suggestionTypes.includes('pastedContent')) &&
    !(
      currentToken.type === 'JSONPath' ||
      (currentToken.type === 'Error' &&
        JSONPATH_PATTERN_PARTIAL.exec(currentToken.textValue) &&
        !currentToken.textValue.endsWith('$'))
    )
  ) {
    return [getSearchSuggestion(textValue)];
  }

  return [];
}

/** @internal */
export function getFallbackKeySuggestions(
  currentToken: FilterFieldValueNode,
  suggestionTypes: FilterFieldSuggestionType,
  fallbackKeys?: FallbackKeys,
  filterStatementSuggestions?: FilterFieldSuggestionProps[],
): FilterFieldSuggestionProps[] {
  if (!fallbackKeys || fallbackKeys.length === 0) {
    return [];
  }

  const { value } = currentToken;
  const suggestions: FilterFieldSuggestionProps[] = [];

  if (suggestionTypes.includes('key') && value !== '') {
    const textValue = currentToken.textValue;
    for (const key of fallbackKeys) {
      if (Array.isArray(key.comparisonOperators)) {
        for (const operator of key.comparisonOperators) {
          const fallbackKeySuggestion = getFallbackKeySuggestion(
            key.value,
            operator,
            textValue,
          );

          // Only add the fallback key suggestion if there isn't already a suggestion for the same statement
          // coming from the statement suggestions.
          if (
            !(
              operator === 'equals' &&
              filterStatementSuggestions?.some(
                (statementSuggestion) =>
                  statementSuggestion.value === fallbackKeySuggestion.value,
              )
            )
          ) {
            suggestions.push(fallbackKeySuggestion);
          }
        }
      } else {
        suggestions.push(
          getFallbackKeySuggestion(key.value, 'matches-phrase', textValue),
        );
      }
    }
  }

  return suggestions;
}

/** @internal */
export function getFilterStatementSuggestions(
  currentToken: FilterFieldLeafNode,
  suggestionTypes: FilterFieldSuggestionType,
  filterStatementKeysMap?: FilterStatementKeysMap,
): FilterFieldSuggestionProps[] {
  const { textValue } = currentToken;

  if (
    !filterStatementKeysMap ||
    !suggestionTypes.includes('key') ||
    textValue === ''
  ) {
    return [];
  }

  const suggestions: FilterFieldSuggestionProps[] = [];

  // Match the current value against the keys map
  if (filterStatementKeysMap.values.size > 0) {
    // Loop through the map and check if the current value matches any values in the map (also partial matches, case-insensitive)
    const lowerTextValue = textValue.toLowerCase();
    for (const [value, keys] of filterStatementKeysMap.values.entries()) {
      if (value.toLowerCase().includes(lowerTextValue)) {
        for (const key of keys) {
          suggestions.push(getStatementSuggestionForMatchingValue(key, value));
        }
      }
    }
  }

  if (filterStatementKeysMap.functions.size > 0) {
    // Loop through the functions map and check if the function returns true for the current value
    for (const [key, func] of filterStatementKeysMap.functions.entries()) {
      if (func(currentToken)) {
        suggestions.push(
          getStatementSuggestionForMatchingValue(key, currentToken.textValue),
        );
      }
    }
  }

  return suggestions;
}

/**
 * @internal
 */
export function getFilterStatementKeysMap(
  validatorMap?: FilterFieldValidatorMap,
): FilterStatementKeysMap | undefined {
  if (
    !validatorMap ||
    Array.isArray(validatorMap.keyPredicates) ||
    !validatorMap.keyPredicates
  ) {
    return undefined;
  }

  const valuesMap: FilterStatementValuesMap = new Map<string, string[]>();
  const functionsMap: FilterStatementFunctionMap = new Map<
    string,
    FilterFieldValueMatchFn
  >();

  for (const [key, keyPredicate] of Object.entries(
    validatorMap.keyPredicates,
  )) {
    if (!isFilterFieldValidatorMapTypeSpecification(keyPredicate)) {
      if (typeof keyPredicate.suggestStatementOnValueMatch === 'function') {
        functionsMap.set(key, keyPredicate.suggestStatementOnValueMatch);
      } else if (
        keyPredicate.suggestStatementOnValueMatch &&
        keyPredicate.valuePredicate
      ) {
        const valuePredicate = keyPredicate.valuePredicate;

        // If valuePredicate is an array of literal values add each of them to the valuesMap with the corresponding key.
        if (Array.isArray(valuePredicate)) {
          for (const value of valuePredicate) {
            if (!isFilterFieldValueSuggestionGroupConfig(value)) {
              addKeyValuePairToMap(valuesMap, key, value);
            }
          }
        } else if (
          valuePredicate &&
          typeof valuePredicate !== 'function' &&
          !isFilterFieldValueSuggestionGroupConfig(valuePredicate)
        ) {
          // The valuePredicate is a single literal value. Add it to the valuesMap with the corresponding key.
          addKeyValuePairToMap(valuesMap, key, valuePredicate);
        }
      }
    }
  }

  return valuesMap.size > 0 || functionsMap.size > 0
    ? { values: valuesMap, functions: functionsMap }
    : undefined;
}

function addKeyValuePairToMap(
  valuesMap: Map<string, string[]>,
  key: string,
  value: FilterFieldValuePredicateItem,
) {
  if (!isFilterFieldValidatorMapTypeSpecification(value)) {
    const stringValue: string = getValuePredicateTextValue(value);

    const existingKeys = valuesMap.get(stringValue) ?? [];
    if (!existingKeys.includes(key)) {
      valuesMap.set(stringValue, [...existingKeys, key]);
    }
  }
}

/**
 * @internal
 */
export function getFallbackKeys(
  validatorMap?: FilterFieldValidatorMap,
): FallbackKeys | undefined {
  if (!validatorMap || Array.isArray(validatorMap.keyPredicates)) {
    return undefined;
  }

  const keys: FallbackKeys = [];

  for (const key in validatorMap.keyPredicates) {
    const keyPredicate = validatorMap.keyPredicates[key];
    if (
      !isFilterFieldValidatorMapTypeSpecification(keyPredicate) &&
      keyPredicate.fallbackKey
    ) {
      keys.push({
        value: key,
        comparisonOperators: Array.isArray(keyPredicate.fallbackKey)
          ? keyPredicate.fallbackKey
          : undefined,
      });
    }
  }

  return keys.length > 0 ? keys : undefined;
}

function getIconForCustomType(
  type: FilterFieldPrimitive | string,
  customTypes: FilterFieldCustomTypes,
) {
  for (const [typeName, customType] of Object.entries(customTypes)) {
    if (
      typeName === type &&
      typeof customType === 'object' &&
      customType.icon !== undefined
    ) {
      return customType.icon;
    }
  }
  return null;
}

function getIconForValueType(
  type: FilterFieldPrimitive | (string & {}),
  customTypes?: FilterFieldCustomTypes,
) {
  switch (type) {
    case 'Number': {
      return <HashtagIcon />;
    }
    case 'Boolean': {
      return <BooleanIcon />;
    }
    case 'Duration': {
      return <StopwatchIcon />;
    }
    case 'JSONPath': {
      return <JsonIcon />;
    }
    case 'IPAddress': {
      return <IPaddressIcon />;
    }
    case 'UID': {
      return <UIDIcon />;
    }
    case 'SmartscapeId': {
      return <UIDIcon />;
    }
    case 'Timestamp': {
      return <ClockIcon />;
    }
    case 'String':
    case 'Any':
      return <AbcIcon />;
  }
  if (customTypes) {
    return getIconForCustomType(type, customTypes);
  }
}

function getDefaultKeySuggestion(
  value: string,
  valueNeedsEscaping: boolean = false,
): FilterFieldSuggestionProps {
  // Check if the value starts and ends with a quote.
  const match = /^"(.+)(?<!\\)"$/.exec(value);
  const textValue = match ? match[1] : value;

  return {
    trailing: ' ',
    suggestionType: 'hint-useAsKey',
    value: valueNeedsEscaping ? `"${value}"` : value,
    id: 'strato-filterfield-suggestion-use-as-key',
    displayValue: (
      <FormattedMessage
        {...filterFieldMessages.suggestions.useAsKey}
        values={{
          value: (
            <>
              &nbsp;<mark>{textValue}</mark>&nbsp;
            </>
          ),
        }}
      />
    ),
  };
}

function getJSONPathKeySuggestion(
  key: string,
  valueType: FilterFieldPrimitive | (string & {}) = 'Any',
): FilterFieldSuggestionProps {
  return {
    value: `${key}$.`,
    icon: getIconForValueType(valueType),
    trailing: '',
    suggestionType: 'JSONPath',
    cursorBeforeTrailing: true,
    details: (
      <FormattedMessage
        defaultMessage="Filter JSON attributes"
        description="Details shown for JSONPath key suggestions."
        id="/SFvkA0WT3AVdLhH"
      />
    ),
    insertionStrategy: 'replace-statement',
  };
}
